    html = html.replace('>Agent workflow</a>', '>Agent</a>')
    api_old = f"<div id=\"apip\" class=\"pattern\" hidden>Documented API: <b>{patterns['documented']} of 100</b> · Read verified: <b>{patterns['readable']} of 100</b> · Write verified: <b>{patterns['writable']} of 100</b></div>"
    api_new = f"<div id=\"apip\" class=\"pattern\" hidden><b>API capability coverage</b><div>Documented API · {patterns['documented']} of 100</div><div class=\"bar\"><i style=\"width:{patterns['documented']}%\"></i></div><div>Read operations · {patterns['readable']} of 100</div><div class=\"bar\"><i style=\"width:{patterns['readable']}%\"></i></div><div>Write operations · {patterns['writable']} of 100</div><div class=\"bar\"><i style=\"width:{patterns['writable']}%\"></i></div><p class=\"muted\">These counts reflect verified evidence, not inferred support.</p></div>"
    html = html.replace(api_old, api_new)
    mcp_old = f"<div id=\"mcpp\" class=\"pattern\" hidden>{' · '.join(f'{_label(k)}: {v} of 100' for k,v in patterns['mcp'].items())}</div>"
    mcp_rows = "".join(f"<div>{_label(k)} · {v} of 100</div><div class=\"bar\"><i style=\"width:{v}%\"></i></div>" for k, v in patterns["mcp"].items())
    html = html.replace(mcp_old, f"<div id=\"mcpp\" class=\"pattern\" hidden><b>MCP availability</b>{mcp_rows}<p class=\"muted\">Official and preview classifications are separated from unverified results.</p></div>")
    blocker_text = ' · '.join(f'{k}: {v} of 100' for k,v in patterns['blockers'].items()) or 'Coverage was insufficient to draw a defensible conclusion.'
    blocker_old = f"<div id=\"blockp\" class=\"pattern\" hidden>{blocker_text}</div>"
    blocker_rows = "".join(f"<div>{k} · {v} of 100</div><div class=\"bar\"><i style=\"width:{v}%\"></i></div>" for k, v in patterns["blockers"].items())
    html = html.replace(blocker_old, f"<div id=\"blockp\" class=\"pattern\" hidden><b>Primary review blockers</b>{blocker_rows}<p class=\"muted\">A blocker means the decisive evidence was not sufficient for an automatic verdict.</p></div>")
    html = html.replace('${esc(r.name)}</b>', '${esc(r.name)}</b>${r.human_verified?\'<span class="badge good">Human verified</span>\':\'\'}')
    html = html.replace('Human verified', 'Manually audited')
    html = html.replace('${label(r.buildability_verdict)}</span>', '${label(r.human_verified_scoped_verdict||r.buildability_verdict)}</span>')
    html = html.replace('<th>Authentication</th><th>API capability</th><th>Credential access</th><th>MCP</th><th>Toolkit decision</th><th>Confidence</th><th>Primary review reason</th><th>Details</th>', '<th>Authentication</th><th>API</th><th>Integration path</th><th>Confidence</th><th>Review</th><th>Details</th>')
    old_cells = "<td>${(r.authentication?.methods||[]).map(label).join(', ')||'Not verified'}</td><td>${api(r)}</td><td>${label(r.credential_access?.independent_developer_access)}</td><td>${label(r.mcp_status?.status)}</td><td><span class=\"badge ${r.review_status==='evidence-finalized'?'good':''}\">${label(r.human_verified_scoped_verdict||r.buildability_verdict)}</span></td><td>${label(r.confidence)}</td><td>${esc(primary(r))}</td><td><button onclick=\"openDrawer('${r.app_id}')\">View details</button></td>"
    new_cells = "<td>${r.manual_authentication||((r.authentication?.methods||[]).map(label).join(', ')||'Not verified')}</td><td>${r.manual_api||api(r)}</td><td><span class=\"path\">Customer: ${r.manual_customer_path||label(r.credential_access?.independent_developer_access)}<br>Public: ${r.manual_public_path||'Not established'}</span></td><td>${label(r.confidence)}</td><td><span class=\"badge ${r.human_verified?'good':''}\">${r.human_verified?'Manually audited':(r.review_status==='evidence-finalized'?'Agent finalized':'Needs verification')}</span></td><td><button onclick=\"openDrawer('${r.app_id}')\">View details</button></td>"
    html = html.replace(old_cells, new_cells)
    html = html.replace('${label(r.human_verified_scoped_verdict||r.buildability_verdict)} · ${label(r.confidence)}', '${r.human_verified?`Manual audit result: ${r.human_verified_scoped_verdict}`:`Agent result: ${label(r.buildability_verdict)}`} · ${label(r.confidence)}<br>${r.human_verified?`Original agent result: ${label(r.buildability_verdict)}`:``}')
    html = html.replace('</style>', '.path{display:block;max-width:190px;line-height:1.25;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}tbody tr{height:72px}thead th{position:sticky;top:57px;background:var(--bg);z-index:3}</style>')
    html = html.replace('thead th{position:sticky;top:57px;background:var(--bg);z-index:3}', 'thead th{position:static;background:var(--bg);z-index:auto}')
    html = html.replace('${r.human_verified?\'<span class="badge good">Manually audited</span>\':\'\'}', '')
    html = html.replace('</script></body>', "const sectionObserver=new IntersectionObserver(es=>es.forEach(e=>{if(e.isIntersecting){document.querySelectorAll('nav a').forEach(a=>a.classList.toggle('active',a.getAttribute('href')==='#'+e.target.id));}}),{rootMargin:'-30% 0px -60%'});document.querySelectorAll('main section[id]').forEach(s=>sectionObserver.observe(s));document.addEventListener('keydown',e=>{if(e.key==='Escape')closeDrawer()});</script></body>")
    generated_at = datetime.now(UTC).isoformat()
    html = html.replace("</main>", f"<footer class='mono' style='max-width:1240px;margin:0 auto;padding:24px 5vw'>Generated at {generated_at} · dataset presentation only</footer></main>")
    path.write_text(html, encoding="utf-8")
